        // Convenience lookup: returns the FIRST part found for a bin, or null if the bin has no data.
        public static (string PartNumber, string PartName)? GetFirstPart(string binLocation)
        {
            if (string.IsNullOrWhiteSpace(binLocation)) return null;
            if (BinToParts.TryGetValue(binLocation.Trim(), out var parts) && parts.Count > 0)
                return parts[0];
            return null;
        }

        // Returns ALL parts stored in a bin (useful for the bins that share space with multiple materials).
        public static List<(string PartNumber, string PartName)> GetAllParts(string binLocation)
        {
            if (string.IsNullOrWhiteSpace(binLocation)) return new List<(string PartNumber, string PartName)>();
            return BinToParts.TryGetValue(binLocation.Trim(), out var parts) ? parts : new List<(string PartNumber, string PartName)>();
        }
    }
